var e=[{id:`L2_1`,type:`dialog`,speaker:null,text:{KOREA:`거기 서라. 노란 옷의 마녀!`,JPN:`待ちなさい！　黄衣の魔女！`,ENG:`Stop right there, Witch in Yellow!`,TWN:`給我站住，黃衣魔女！`},stage:{bg:`DORMITORY_2`,slots:{L:null,C:null,R:null}}},{id:`L3_1`,type:`dialog`,speaker:null,text:{KOREA:`후후, 잘도 여기까지 도착했구나. 소녀 마녀 네크로노미코여!`,JPN:`ふふ。よくここまでたどり着いたな、魔法少女ネクロノミコ！`,ENG:`So, you’re finally here, Necronomiko the Girl Witch.`,TWN:`呵呵，魔法少女！你竟然能夠找到這裡來。`},stage:{bg:`DORMITORY_2`,slots:{L:null,C:null,R:null}}},{id:`L4_1`,type:`dialog`,speaker:null,text:{KOREA:`그렇다면 그 상으로 너의 출생의 비밀을 알려주도록 하마.`,JPN:`褒美にお前の出生の秘密を教えてやろう。`,ENG:`As a reward, I’ll tell you the secret of your birth.`,TWN:`那我就告訴你你的身世作為獎賞吧。`},stage:{bg:`DORMITORY_2`,slots:{L:null,C:null,R:null}}},{id:`L5_1`,type:`dialog`,speaker:null,text:{KOREA:`너는 사실, 나의……`,JPN:`実はお前は、私の……`,ENG:`You’re actually my—`,TWN:`你其實是我的……`},stage:{bg:`DORMITORY_2`,slots:{L:null,C:null,R:null}}},{id:`L7_1`,type:`dialog`,speaker:null,text:{KOREA:`……으, 으악!! 무슨 짓이냐!`,JPN:`……うっ、ぐああ！！　なんの真似だ！`,ENG:`Urgh! What are you doing?!`,TWN:`……可惡！！你這是在做什麼！`},stage:{bg:`DORMITORY_2`,slots:{L:null,C:null,R:null}}},{id:`L8_1`,type:`dialog`,speaker:null,text:{KOREA:`알고 있어. 당신이 나의 사돈에 팔촌이라는 사실은.`,JPN:`あなたが私の遠い親戚ってことなんて、とっくに知っているわ。`,ENG:`I already know. That you’re my third-cousin-in-law.`,TWN:`我知道，你是我的遠房親戚。`},stage:{bg:`DORMITORY_2`,slots:{L:null,C:null,R:null}}},{id:`L9_1`,type:`dialog`,speaker:null,text:{KOREA:`그, 그런데 어째서…….`,JPN:`で、ではどうして……`,ENG:`Th-then why did you...`,TWN:`那你為何……`},stage:{bg:`DORMITORY_2`,slots:{L:null,C:null,R:null}}},{id:`L10_1`,type:`dialog`,speaker:null,text:{KOREA:`그야…….`,JPN:`それは……`,ENG:`Because...`,TWN:`因為……`},stage:{bg:`DORMITORY_2`,slots:{L:null,C:null,R:null}}},{id:`L14_1`,type:`dialog`,speaker:`YOONA_STREGA_NULL_NULL`,text:{KOREA:`……`,JPN:`……`,ENG:`...`,TWN:`……`},stage:{bg:`DORMITORY_2`,slots:{L:null,C:{char_id:`YOONA_STREGA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L15_1`,type:`dialog`,speaker:`YOONA_STREGA_NULL_NULL`,text:{KOREA:`괴, 굉장해!! 소녀 마녀 네크로노미코!!`,JPN:`やっぱりすごい！！　魔法少女ネクロノミコ！！`,ENG:`Necronomiko the Girl Witch is the greatest!`,TWN:`好好看！魔女少女亡靈之書！`},stage:{bg:`DORMITORY_2`,slots:{L:null,C:{char_id:`YOONA_STREGA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L16_1`,type:`dialog`,speaker:`YOONA_STREGA_NULL_NULL`,text:{KOREA:`가슴을 울리는 웅장한 BGM, 긴장감 넘치는 마지막 대결……`,JPN:`胸に響く壮大なBGM、手に汗を握る最後の決戦……`,ENG:`The theme song that rings in your heart, and the thrilling final duel...`,TWN:`BGM好激昂，最後的對決也好緊張……`},stage:{bg:`DORMITORY_2`,slots:{L:null,C:{char_id:`YOONA_STREGA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L17_1`,type:`dialog`,speaker:`YOONA_STREGA_NULL_NULL`,text:{KOREA:`하지만 무엇보다도 형언할 수 없는 물리 마법 액션 연출이 최고야!!`,JPN:`でもなにより、言葉では言い表せない物理魔法のアクション演出が最高！！`,ENG:`And above all things, the kinetic magic action is so fantastic!`,TWN:`不過最精彩的還是無法用言語形容的物理魔法動作！！`},stage:{bg:`DORMITORY_2`,slots:{L:null,C:{char_id:`YOONA_STREGA_NULL_NULL`,face:`UNIT_LAUGH`},R:null}}},{id:`L18_1`,type:`dialog`,speaker:`YOONA_STREGA_NULL_NULL`,text:{KOREA:`잉그리드가 그렇게 침이 마르도록 칭찬하던 이유를 알겠어.`,JPN:`イングリッドがあんなにべた褒めしてた理由がよくわかったわ。`,ENG:`Now I know why Ingrid likes it so much.`,TWN:`難怪英格麗會讚不絕口！`},stage:{bg:`DORMITORY_2`,slots:{L:null,C:{char_id:`YOONA_STREGA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L19_1`,type:`dialog`,speaker:`YOONA_STREGA_NULL_NULL`,text:{KOREA:`……흐음.`,JPN:`……ふむ。`,ENG:`Hmm...`,TWN:`……嗯嗯。`},stage:{bg:`DORMITORY_2`,slots:{L:null,C:{char_id:`YOONA_STREGA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L20_1`,type:`dialog`,speaker:`YOONA_STREGA_NULL_NULL`,text:{KOREA:`그래, 정했어.`,JPN:`うん、決めた。`,ENG:`Yes, I made up my mind.`,TWN:`我決定了！`},stage:{bg:`DORMITORY_2`,slots:{L:null,C:{char_id:`YOONA_STREGA_NULL_NULL`,face:`UNIT_SERIOUS`},R:null}}},{id:`L21_1`,type:`dialog`,speaker:`YOONA_STREGA_NULL_NULL`,text:{KOREA:`나도 소녀 마녀 네크로노미코처럼 대단한 물리 마법사가 될래!`,JPN:`私も魔法少女ネクロノミコみたいな偉大な物理魔法使いになる！`,ENG:`I will become a kinetic magic expert, just like Necronomiko the Girl Witch!`,TWN:`我也要成為一個像魔法少女一樣偉大的物理魔法師！`},stage:{bg:`DORMITORY_2`,slots:{L:null,C:{char_id:`YOONA_STREGA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L22_1`,type:`dialog`,speaker:`YOONA_STREGA_NULL_NULL`,text:{KOREA:`좋아!! 그럼 오늘부터 팔굽혀펴기 100개, 윗몸일으키기 100개, 10km 달리기야!`,JPN:`よし！　さっそく今日から腕立て伏せ100回、腹筋100回、10kmの走り込みよ！`,ENG:`Okay, I’m doing 100 push-ups, 100 sit-ups, and a 10K run every day from now on!`,TWN:`就這麼決定！從今天開始，每天要做伏地挺身100下、仰臥起坐100下、慢跑10公里！`},stage:{bg:`DORMITORY_2`,slots:{L:null,C:{char_id:`YOONA_STREGA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}}];export{e as default};